import React, { useState } from "react";
import { Menu, X } from "lucide-react";
import { Link } from "react-router-dom";
import "./navbar.css";

const NAV_LINKS = [
  { label: "الرئيسية", to: "/" },
  { label: "من نحن", to: "/AboutUs" },
  { label: "منتجاتنا", to: "/Products" },
  { label: "تواصل معنا", to: "/ContactUs" },
];

export default function Header() {
  const [isOpen, setIsOpen] = useState(false);

  const closeMenu = () => setIsOpen(false);

  return (
    <nav className="navbar">
      <div className="container navbar-container">
        <div className="navbar-logo-wrapper">
          <div className="navbar-brand">
            biscoza
            <sup className="trademark">®</sup>
          </div>
        </div>

        {/* Desktop Menu */}
        <div className="navbar-links desktop-only">
          {NAV_LINKS.map((link) => (
            <Link
              key={link.label}
              to={link.to}
              className={`nav-link ${link.label === "من نحن" ? "active" : ""}`}
            >
              {link.label}
            </Link>
          ))}
        </div>

        {/* Mobile Menu Button */}
        <div className="mobile-only">
          <button onClick={() => setIsOpen(!isOpen)} className="menu-toggle">
            {isOpen ? <X size={28} /> : <Menu size={28} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="mobile-menu">
          {NAV_LINKS.map((link) => (
            <Link
              key={link.label}
              to={link.to}
              className="mobile-nav-link"
              onClick={closeMenu} // يغلق القائمة عند النقر على الرابط
            >
              {link.label}
            </Link>
          ))}
        </div>
      )}
    </nav>
  );
}
